// Function implementation
// ============================================

inline RollbackObservation test_observer_state_rollback() {
    using namespace reaction;

    // 1. Create RecordingNode instances
    RecordingNode nodeA;
    RecordingNode nodeB;

    // Two sensor nodes to represent different dependencies
    SensorNode sensor1;
    SensorNode sensor2;

    // 2. Get observer graph instance
    auto& graph = ObserverGraph::instance();

    // 3. Register nodes
    graph.addObserverNode(&nodeA);
    graph.addObserverNode(&nodeB);
    graph.addSensorNode(&sensor1);
    graph.addSensorNode(&sensor2);

    // 4. Set up initial dependency: nodeA depends on sensor1
    graph.setDependency(&sensor1, &nodeA);

    // 5. Save node state for rollback
    ObserverGraph::StateToken stateToken = graph.saveState();

    // 6. Replace dependencies transactionally:
    //    nodeA now depends on sensor2, nodeB also depends on sensor2
    graph.beginTransaction();
    graph.clearDependencies(&nodeA);
    graph.setDependency(&sensor2, &nodeA);
    graph.setDependency(&sensor2, &nodeB);
    graph.commitTransaction();

    // 7. Trigger notification on second sensor
    graph.notifySensorChanged(&sensor2);

    // 8. Record notification count after second binding
    int notificationsAfterSecondBinding =
        nodeA.notificationCount() + nodeB.notificationCount();

    // 9. Execute rollback
    graph.rollbackToState(stateToken);

    // 10. Trigger notification on first sensor (original dependency)
    graph.notifySensorChanged(&sensor1);

    // 11. Record notification count after rollback
    int notificationsAfterRollback =
        nodeA.notificationCount() + nodeB.notificationCount();

    // 12. Return notification counts
    return RollbackObservation{
        notificationsAfterSecondBinding,
        notificationsAfterRollback
    };
}

