#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

class CacheProbeNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        // In a typical probe node, we just mark the node as changed and notify dependents.
        // Exact semantics may vary with the library, but this is a reasonable default.
        if (changed) {
            notifyObservers();
        }
    }
};

struct CacheStatsSnapshot {
    size_t graphEntriesBeforeCleanup;
    size_t graphEntriesAfterCleanup;
    double graphHitRatioAfterCleanup;
};

inline CacheStatsSnapshot test_observer_cache_stats() {
    using namespace reaction;

    // 1. Create CacheProbeNode instances
    auto* nodeA = new CacheProbeNode();
    auto* nodeB = new CacheProbeNode();
    auto* nodeC = new CacheProbeNode();

    // 2. Get observer graph instance
    auto& graph = ObserverGraph::instance();

    // 3. Register nodes
    graph.registerNode(nodeA);
    graph.registerNode(nodeB);
    graph.registerNode(nodeC);

    // 4. Set up direct observer relationship
    //    B observes A directly.
    graph.addObserver(nodeA, nodeB);

    // 5. Set up transitive observer relationship
    //    C observes B, so C is a transitive observer of A through B.
    graph.addObserver(nodeB, nodeC);

    // 6. Create NodeSet to store collected observers
    ObserverGraph::NodeSet collectedObservers;

    // 7. Populate cache data by collecting observers for A
    //    This should populate internal cache structures within ObserverGraph.
    graph.collectObservers(nodeA, collectedObservers);

    // 8. Get cache statistics before cleanup
    CacheStatsSnapshot snapshot{};
    {
        auto stats = graph.cacheStats();
        snapshot.graphEntriesBeforeCleanup = stats.entries;
    }

    // 9. Trigger cache cleanup
    graph.cleanupCache();

    // 10. Get cache statistics after cleanup
    {
        auto stats = graph.cacheStats();
        snapshot.graphEntriesAfterCleanup = stats.entries;
        snapshot.graphHitRatioAfterCleanup = stats.hitRatio;
    }

    // 11. Close all nodes
    //     Unregister and delete nodes to avoid leaks and dangling pointers.
    graph.unregisterNode(nodeA);
    graph.unregisterNode(nodeB);
    graph.unregisterNode(nodeC);
    delete nodeA;
    delete nodeB;
    delete nodeC;

    // 12. Return cache stats snapshot
    return snapshot;
}

}  // namespace test_reaction
