namespace test_reaction {

struct ResourceAtomicResult {
    int finalValue;
    bool operationReportedChange;
};

inline ResourceAtomicResult test_resource_atomic(int initialValue, int delta) {
    // 1. Create a Resource instance
    // Assuming reaction::Resource is templated over the underlying type.
    reaction::Resource<std::atomic<int>> resource{std::atomic<int>{initialValue}};

    // 2. Create a variable to track whether operation reported a change
    bool operationReportedChange = false;

    // 3. Perform an atomic operation that adds delta to the value
    //    Dependending on the exact API of reaction::Resource, this uses a
    //    generic 'atomic' update that returns whether the value changed.
    operationReportedChange = resource.atomic([delta](std::atomic<int>& v) {
        int old = v.load(std::memory_order_relaxed);
        int desired = old + delta;
        v.store(desired, std::memory_order_relaxed);
        return desired != old;  // whether operation reported a change
    });

    // 4. Get the final value
    int finalValue = resource.get().load(std::memory_order_relaxed);

    // 5. Return resource atomic result
    return ResourceAtomicResult{finalValue, operationReportedChange};
}

}  // namespace test_reaction
