    SboTraitSummary result{};

    // TinyPod: usually trivially small, expected to always be SBO
    result.tinyAlwaysSbo = (TinyTraits::strategy == sbo_strategy::always);
    result.tinyForceHeap = (TinyTraits::strategy == sbo_strategy::never);

    // MediumPod: size near typical thresholds, expect conditional SBO
    result.mediumConditionalSbo =
        (MediumTraits::strategy == sbo_strategy::conditional);
    result.mediumForceHeap =
        (MediumTraits::strategy == sbo_strategy::never);

    // LargePod: large payload, usually forced to heap
    result.largeForceHeap = (LargeTraits::strategy == sbo_strategy::never);

    // Configuration thresholds
    result.alwaysThreshold      = config.always_sbo_threshold;
    result.conditionalThreshold = config.conditional_sbo_threshold;
    result.maxStackUsage        = config.max_stack_usage;

    return result;
}

}  // namespace test_reaction
