    auto metricsBefore = cache.get(key);

    // 5. Cache node metrics
    // If metricsBefore was not set, create a dummy metrics object.
    if (!metricsBefore) {
        typename NodeMetricsCache::mapped_type metrics{};
        cache.insert_or_assign(key, metrics);
    } else {
        cache.insert_or_assign(key, *metricsBefore);
    }

    // 6. Query metrics after caching
