inline RawExpressionSnapshot test_raw_expression_builders(int a, int b, int c) {
    using namespace reaction;

    // 1. Create reactive variables
    auto A = var(a);
    auto B = var(b);
    auto C = var(c);

    // 2. Build sum expression: sum = A + B
    auto sumExpr = expr(
        make_binary_expr(std::plus<int>{}, A, B)
    );

    // 3. Build negated expression: negated = -(A + B)
    auto negatedExpr = expr(
        make_unary_expr(std::negate<int>{},
            make_binary_expr(std::plus<int>{}, A, B)
        )
    );

    // 4. Build chained expression: chained = -(A + B) * C
    auto chainedExpr = expr(
        make_binary_expr(std::multiplies<int>{},
            make_unary_expr(std::negate<int>{},
                make_binary_expr(std::plus<int>{}, A, B)
            ),
            C
        )
    );

    RawExpressionSnapshot snapshot{};

    // 5. Get initial expression values
    snapshot.initialSum          = sumExpr.value();
    snapshot.initialNegatedSum   = negatedExpr.value();
    snapshot.initialChainedValue = chainedExpr.value();

    // 6. Update variables to trigger recomputation
    // For demonstration, nudge A and C in a deterministic way
    A = a + 1;
    C = c + 2;

    // 7. Get updated expression values
    snapshot.updatedSum          = sumExpr.value();
    snapshot.updatedNegatedSum   = negatedExpr.value();
    snapshot.updatedChainedValue = chainedExpr.value();

    // 8. Return raw expression snapshot
    return snapshot;
}

}  // namespace test_reaction

