    reaction::atomicAddAssign(atomic, int32_t{5});
    bool addReported = atomic.lastReportedChange();

    // 5–6. Apply atomic multiply assignment (*= 3) and record change
    reaction::atomicMultiplyAssign(atomic, int32_t{3});
    bool multiplyReported = atomic.lastReportedChange();

    // 7–8. Apply atomic bitwise AND assignment (&= 0xFF) and record change
    reaction::atomicBitwiseAndAssign(atomic, int32_t{0xFF});
    bool andReported = atomic.lastReportedChange();

    // 9–10. Apply atomic left shift assignment (<<= 1) and record change
    reaction::atomicLeftShiftAssign(atomic, int32_t{1});
    bool leftShiftReported = atomic.lastReportedChange();

